Creating a Dataset from Scratch


Code
from datasets import Dataset

data = {
    "text": ["I love this!", "This is bad!", "Absolutely amazing!", "Not good at all!"],
    "label": [1, 0, 1, 0],
}

dataset = Dataset.from_dict(data)
print(dataset)


Dataset({
    features: ['text', 'label'],
    num_rows: 4
})

